module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

reg [2:0] mul_en_out_reg;
reg [size-1:0] mul_a_reg, mul_b_reg;
wire [size-1:0] temp [size-1:0];
reg [size:0] sum [3:0];
reg [size*2-1:0] mul_out_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_en_out_reg <= 0;
        mul_en_out <= 0;
    end else begin
        mul_en_out_reg <= {mul_en_out_reg[1:0], mul_en_in};
        mul_en_out <= mul_en_out_reg[2];
    end
end

always @(posedge clk) begin
    if (mul_en_in) begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end else begin
        mul_a_reg <= 0;
        mul_b_reg <= 0;
    end
end

genvar i;
generate
    for (i = 0; i < size; i = i + 1) begin
        if (i % 2 == 0) begin
            assign temp[i] = mul_b_reg[i] ? mul_a_reg : 0;
        end else begin
            assign temp[i] = mul_b_reg[i] ? ~mul_a_reg : 0;
        end
    end
endgenerate

always @(posedge clk) begin
    sum[0] <= temp[0] + temp[1];
    sum[1] <= temp[2] + temp[3];
    sum[2] <= temp[4] + temp[5];
    sum[3] <= temp[6] + temp[7];
end

always @(posedge clk) begin
    mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3];
end

always @(posedge clk) begin
    if (mul_en_out_reg[2]) begin
        mul_out <= mul_out_reg;
    end else begin
        mul_out <= 0;
    end
end

endmodule
